// templates/mod.rs
//
// All HTML generated by Rust functions returning String.
// No template engine — zero overhead, zero mismatches.
//
// Security: every user-supplied string passes through escape_html() before
// insertion.  Template literals are trusted Rust strings only.

use crate::config::CONFIG;
use crate::models::*;
use crate::utils::{files::format_file_size, sanitize::escape_html};
use once_cell::sync::Lazy;
use std::sync::RwLock;

// ─── Live site name (DB-overridable, falls back to CONFIG.forum_name) ─────────

static LIVE_SITE_NAME: Lazy<RwLock<String>> = Lazy::new(|| RwLock::new(CONFIG.forum_name.clone()));
static LIVE_SITE_SUBTITLE: Lazy<RwLock<String>> =
    Lazy::new(|| RwLock::new("select board to proceed".to_string()));

/// Call this at startup (after first DB read) and after admin saves a new name.
pub fn set_live_site_name(name: &str) {
    if let Ok(mut guard) = LIVE_SITE_NAME.write() {
        *guard = if name.trim().is_empty() {
            CONFIG.forum_name.clone()
        } else {
            name.to_string()
        };
    }
}

pub fn set_live_site_subtitle(subtitle: &str) {
    if let Ok(mut guard) = LIVE_SITE_SUBTITLE.write() {
        *guard = if subtitle.trim().is_empty() {
            "select board to proceed".to_string()
        } else {
            subtitle.to_string()
        };
    }
}

/// Read the current live site name.
fn live_site_name() -> String {
    LIVE_SITE_NAME
        .read()
        .map(|g| g.clone())
        .unwrap_or_else(|_| CONFIG.forum_name.clone())
}

fn live_site_subtitle() -> String {
    LIVE_SITE_SUBTITLE
        .read()
        .map(|g| g.clone())
        .unwrap_or_else(|_| "select board to proceed".to_string())
}

// ─── Shared JS injected once per page ────────────────────────────────────────

const TOGGLE_SCRIPT: &str = r#"<script>
function togglePostForm() {
  var wrap = document.getElementById('post-form-wrap');
  var btn = document.querySelector('.post-toggle-btn');
  if (!wrap) return;
  var opening = wrap.style.display === 'none';
  wrap.style.display = opening ? 'block' : 'none';
  if (btn) btn.classList.toggle('active', opening);
  if (opening) {
    var first = wrap.querySelector('input[type="text"], textarea');
    if (first) first.focus();
  }
}
function toggleMobileDrawer() {
  var drawer = document.getElementById('mobile-reply-drawer');
  var fab = document.getElementById('mobile-reply-fab');
  if (!drawer) return;
  var opening = !drawer.classList.contains('open');
  drawer.classList.toggle('open', opening);
  if (fab) fab.classList.toggle('hidden', opening);
  if (opening) {
    var ta = drawer.querySelector('textarea');
    if (ta) { setTimeout(function(){ ta.focus(); }, 120); }
  }
}
function appendReply(id) {
  // Desktop: open the inline form
  var wrap = document.getElementById('post-form-wrap');
  // Mobile: open the drawer instead if we're on a small screen
  var isMobile = window.matchMedia('(max-width: 767px)').matches;
  if (isMobile) {
    var drawer = document.getElementById('mobile-reply-drawer');
    if (drawer && !drawer.classList.contains('open')) toggleMobileDrawer();
    var ta = drawer ? drawer.querySelector('textarea') : null;
    if (ta) { ta.value += '>>' + id + '\n'; ta.focus(); }
  } else {
    if (wrap && wrap.style.display === 'none') togglePostForm();
    var ta = document.getElementById('reply-body');
    if (ta) { ta.value += '>>' + id + '\n'; ta.focus(); }
  }
  return false;
}
function expandMedia(preview) {
  var container = preview.closest('.file-container');
  var expanded = container.querySelector('.media-expanded');
  var closeBtn = container.querySelector('.media-close-btn');
  if (expanded.tagName === 'IMG' && expanded.dataset.src) {
    expanded.src = expanded.dataset.src;
    delete expanded.dataset.src;
  }
  preview.style.display = 'none';
  expanded.style.display = 'block';
  closeBtn.style.display = 'inline-flex';
  if (expanded.tagName === 'VIDEO') {
    expanded.play().catch(function(){});
  }
}
function collapseMedia(btn) {
  var container = btn.closest('.file-container');
  var expanded = container.querySelector('.media-expanded');
  var preview = container.querySelector('.media-preview');
  if (expanded.tagName === 'VIDEO') {
    expanded.pause();
    expanded.currentTime = 0;
  }
  expanded.style.display = 'none';
  expanded.style.maxWidth = '';
  expanded.style.maxHeight = '';
  preview.style.display = 'block';
  btn.style.display = 'none';
}
function expandVideoEmbed(preview, type, id, container) {
  var iframe = document.createElement('iframe');
  if (type === 'youtube') {
    iframe.src = 'https://www.youtube-nocookie.com/embed/' + id + '?autoplay=1&rel=0';
  } else if (type === 'streamable') {
    iframe.src = 'https://streamable.com/e/' + id + '?autoplay=1';
  }
  iframe.className = 'embed-iframe';
  iframe.setAttribute('frameborder', '0');
  iframe.setAttribute('allowfullscreen', '');
  iframe.setAttribute('allow', 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share; fullscreen');
  iframe.setAttribute('referrerpolicy', 'strict-origin-when-cross-origin');
  preview.style.display = 'none';
  var closeBtn = container.querySelector('.media-close-btn');
  if (closeBtn) closeBtn.style.display = 'inline-flex';
  container.appendChild(iframe);
}
function collapseVideoEmbed(btn) {
  var container = btn.closest('.video-embed-container');
  if (!container) return;
  var iframe = container.querySelector('.embed-iframe');
  var preview = container.querySelector('.media-preview');
  if (iframe) { iframe.src = ''; iframe.remove(); }
  if (preview) preview.style.display = '';
  btn.style.display = 'none';
}
</script>"#;

// ─── Auto-compress modal (injected into forms that accept image/video) ────────

/// Returns the compress-modal overlay HTML + all supporting JavaScript.
/// `max_image_bytes` and `max_video_bytes` are injected as JS constants so the
/// client-side size check matches the server-side limit exactly.
fn compress_modal_script(max_image_bytes: usize, max_video_bytes: usize) -> String {
    format!(
        r#"
<!-- Auto-compress modal — shared by new-thread and reply forms on this page -->
<div id="compress-modal" class="compress-modal" style="display:none" role="dialog" aria-modal="true" aria-labelledby="compress-modal-title">
  <div class="compress-modal-box">
    <div class="compress-modal-title" id="compress-modal-title">&#9888; File Too Large</div>
    <div class="compress-modal-info" id="compress-info"></div>
    <div class="compress-progress" id="compress-progress" style="display:none">
      <div class="compress-progress-track"><div class="compress-progress-bar" id="compress-progress-bar"></div></div>
      <div class="compress-progress-text" id="compress-progress-text">Preparing…</div>
    </div>
    <div class="compress-modal-actions" id="compress-actions">
      <button class="compress-cancel-btn" onclick="dismissCompressModal()">Cancel</button>
      <button class="compress-do-btn" id="compress-do-btn" onclick="startCompress()">&#9881; Auto-compress</button>
    </div>
    <div class="compress-done-actions" id="compress-done-actions" style="display:none">
      <button class="compress-cancel-btn" onclick="dismissCompressModal()">Close</button>
    </div>
  </div>
</div>
<script>
(function() {{
  var MAX_IMAGE = {max_image};
  var MAX_VIDEO = {max_video};
  var _input = null, _file = null, _max = 0, _compressing = false;

  // Called from onchange on every file input that accepts images or videos.
  window.checkFileSize = function(input) {{
    var file = input.files && input.files[0];
    if (!file) return;
    var isImg   = file.type.startsWith('image/');
    var isVideo = file.type.startsWith('video/');
    var limit   = isImg ? MAX_IMAGE : (isVideo ? MAX_VIDEO : 0);
    if (limit === 0 || file.size <= limit) return;
    _input = input;
    _file  = file;
    _max   = limit;
    var sizeMiB = (file.size   / 1048576).toFixed(1);
    var limMiB  = (limit       / 1048576).toFixed(1);
    document.getElementById('compress-info').textContent =
      '\u201c' + file.name + '\u201d is ' + sizeMiB + ' MiB \u2014 board limit is ' + limMiB + ' MiB.';
    _setView('actions');
    document.getElementById('compress-modal').style.display = 'flex';
  }};

  window.dismissCompressModal = function() {{
    if (_compressing) return; // block dismiss while running
    document.getElementById('compress-modal').style.display = 'none';
    if (_input) {{ _input.value = ''; }}
    _input = null; _file = null; _compressing = false;
  }};

  window.startCompress = function() {{
    if (!_file || !_input || _compressing) return;
    _compressing = true;
    _setView('progress');
    _setProgress(0, 'Starting\u2026');

    var isImg   = _file.type.startsWith('image/');
    var isVideo = _file.type.startsWith('video/');
    var promise = isImg   ? _compressImage(_file, _max)
                : isVideo ? _compressVideo(_file, _max)
                : Promise.reject(new Error('Unsupported type'));

    promise.then(function(blob) {{
      if (!blob || blob.size > _max) {{
        _setProgress(100, 'Could not compress to the required size. Please use a smaller file.');
        _compressing = false;
        _setView('done');
        return;
      }}
      var ext     = isImg ? 'jpg' : 'webm';
      var newName = _file.name.replace(/\.[^.]+$/, '') + '_compressed.' + ext;
      var dt      = new DataTransfer();
      dt.items.add(new File([blob], newName, {{ type: blob.type }}));
      _input.files = dt.files;
      var finalMiB = (blob.size / 1048576).toFixed(2);
      _setProgress(100, '\u2713 Compressed to ' + finalMiB + ' MiB. Ready to post.');
      _compressing = false;
      setTimeout(function() {{
        document.getElementById('compress-modal').style.display = 'none';
        _input = null; _file = null;
      }}, 1200);
    }}).catch(function(err) {{
      _setProgress(0, 'Error: ' + (err.message || err));
      _compressing = false;
      _setView('done');
    }});
  }};

  function _setView(which) {{
    document.getElementById('compress-actions').style.display = which === 'actions'  ? 'flex' : 'none';
    document.getElementById('compress-progress').style.display = which === 'progress' ? 'block': 'none';
    document.getElementById('compress-done-actions').style.display = which === 'done' ? 'flex' : 'none';
  }}

  function _setProgress(pct, text) {{
    document.getElementById('compress-progress-bar').style.width = pct + '%';
    document.getElementById('compress-progress-text').textContent = text;
  }}

  // ── Image compression via Canvas API ─────────────────────────────────────
  async function _compressImage(file, targetBytes) {{
    var img = await createImageBitmap(file);
    var canvas = document.createElement('canvas');
    var quality = 0.88, scale = 1.0;
    for (var i = 0; i < 22; i++) {{
      canvas.width  = Math.max(1, Math.round(img.width  * scale));
      canvas.height = Math.max(1, Math.round(img.height * scale));
      var ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
      var blob = await new Promise(function(res) {{ canvas.toBlob(res, 'image/jpeg', quality); }});
      var pct = Math.min(95, Math.round((i + 1) / 22 * 100));
      _setProgress(pct, 'Compressing image\u2026 ' + (blob.size / 1048576).toFixed(2) + ' MiB');
      if (blob.size <= targetBytes) return blob;
      if (quality > 0.42) {{ quality -= 0.10; }}
      else {{ scale *= 0.72; quality = 0.72; }}
      if (scale < 0.08) break;
    }}
    return null;
  }}

  // ── Video compression via MediaRecorder API ───────────────────────────────
  async function _compressVideo(file, targetBytes) {{
    var videoEl = document.createElement('video');
    videoEl.src = URL.createObjectURL(file);
    videoEl.muted = true;   // mute speaker output; audio is captured via captureStream below
    videoEl.preload = 'metadata';
    await new Promise(function(res, rej) {{
      videoEl.onloadedmetadata = res;
      videoEl.onerror = function() {{ rej(new Error('Cannot load video metadata')); }};
    }});
    var dur = videoEl.duration;
    if (!dur || !isFinite(dur)) throw new Error('Cannot determine video duration.');

    // Bitrate budget: 85% efficiency factor covers container and muxer overhead.
    // 96 kbps Opus is transparent for speech and music; remaining bits go to video.
    var audioBps = 98304; // 96 kbps
    var totalBps = Math.max(250000, Math.floor(targetBytes * 8 * 0.85 / dur));
    var videoBps = Math.max(120000, totalBps - audioBps);

    // Downscale resolution for high-res sources — the in-browser VP9 encoder
    // cannot cleanly hit low bitrate targets at full 1080p/4K resolution, and
    // the resulting blocking artifacts look worse than a properly downscaled video.
    // Cap the long edge at 1280px and round dimensions to even numbers (VP9 req).
    var srcW = videoEl.videoWidth  || 640;
    var srcH = videoEl.videoHeight || 360;
    var MAX_LONG_EDGE = 1280;
    var scale = Math.min(1, MAX_LONG_EDGE / Math.max(srcW, srcH));
    var canvasW = Math.max(2, Math.round(srcW * scale / 2) * 2);
    var canvasH = Math.max(2, Math.round(srcH * scale / 2) * 2);

    var canvas = document.createElement('canvas');
    canvas.width  = canvasW;
    canvas.height = canvasH;
    var ctx = canvas.getContext('2d');

    // Prefer codecs that include audio; fall back gracefully.
    var mime = ['video/webm;codecs=vp9,opus','video/webm;codecs=vp8,opus','video/webm']
                 .find(function(m) {{ return MediaRecorder.isTypeSupported(m); }});
    if (!mime) throw new Error('Browser does not support MediaRecorder for video/webm.');

    // captureStream(0) = manual frame-driven mode. The browser only emits a new
    // frame to the encoder when we explicitly call videoTrack.requestFrame().
    // This prevents two classes of stuttering:
    //   1. Duplicate frames: requestAnimationFrame fires at display refresh rate
    //      (~60-120 Hz), much faster than most video framerates (24-30 fps).
    //      With captureStream(24), the encoder receives the same frame 2-3 times
    //      with non-uniform timestamps, producing jitter on playback.
    //   2. Auto-generated blank frames: captureStream(N>0) generates frames at
    //      a fixed rate regardless of whether new video content has been drawn,
    //      producing black or frozen frames during any playback stall.
    var stream = canvas.captureStream(0);
    var videoTrack = stream.getVideoTracks()[0];

    // Attach audio tracks from the source video element.
    var srcStream = (typeof videoEl.captureStream === 'function')
                      ? videoEl.captureStream()
                      : (typeof videoEl.mozCaptureStream === 'function')
                          ? videoEl.mozCaptureStream()
                          : null;
    if (srcStream) {{
      srcStream.getAudioTracks().forEach(function(track) {{ stream.addTrack(track); }});
    }}

    var recorder = new MediaRecorder(stream, {{ mimeType: mime, videoBitsPerSecond: videoBps }});
    var chunks = [];
    recorder.ondataavailable = function(e) {{ if (e.data.size > 0) chunks.push(e.data); }};

    // Draw one video frame to canvas and notify the stream encoder.
    function captureFrame() {{
      ctx.drawImage(videoEl, 0, 0, canvasW, canvasH);
      videoTrack.requestFrame();
      var pct = dur > 0 ? Math.min(98, Math.round(videoEl.currentTime / dur * 100)) : 0;
      _setProgress(pct, 'Compressing video\u2026 ' + pct + '%  (real-time)');
    }}

    // requestVideoFrameCallback (Chrome 83+, Safari 15.4+, Firefox 132+) fires
    // exactly once per decoded video frame — perfect frame-accurate capture.
    // Fall back to timeupdate for older browsers: fires ~4 times/sec which gives
    // a low but consistent framerate rather than the stuttering rAF caused.
    var useRVFC = typeof videoEl.requestVideoFrameCallback === 'function';
    function onFrame() {{
      captureFrame();
      if (!videoEl.ended && !videoEl.paused && useRVFC) {{
        videoEl.requestVideoFrameCallback(onFrame);
      }}
    }}

    // Register the frame callback and start the recorder BEFORE calling play()
    // so the first frame and any pre-roll audio are captured, not dropped.
    if (useRVFC) {{
      videoEl.requestVideoFrameCallback(onFrame);
    }} else {{
      videoEl.addEventListener('timeupdate', captureFrame);
    }}
    recorder.start(250);

    // Await play() so we know playback has actually started before waiting for
    // the ended event — on slow devices play() can take a moment to resolve.
    await videoEl.play();

    await new Promise(function(res) {{
      videoEl.onended = function() {{ recorder.stop(); res(); }};
      videoEl.onerror = function() {{ recorder.stop(); res(); }};
    }});

    if (!useRVFC) {{ videoEl.removeEventListener('timeupdate', captureFrame); }}
    await new Promise(function(res) {{ recorder.onstop = res; }});
    URL.revokeObjectURL(videoEl.src);
    if (!chunks.length) throw new Error('No video frames captured.');
    return new Blob(chunks, {{ type: 'video/webm' }});
  }}
}})();
</script>"#,
        max_image = max_image_bytes,
        max_video = max_video_bytes,
    )
}

// ─── Report modal ─────────────────────────────────────────────────────────────

/// Returns the report overlay HTML + JS. Injected once per thread page.
fn report_modal_script() -> &'static str {
    r#"
<div id="report-modal" class="compress-modal" style="display:none" role="dialog" aria-modal="true">
  <div class="compress-modal-box">
    <div class="compress-modal-title">&#9873; Report Post</div>
    <form method="POST" action="/report" id="report-form">
      <input type="hidden" name="_csrf"     id="report-csrf">
      <input type="hidden" name="post_id"   id="report-post-id">
      <input type="hidden" name="thread_id" id="report-thread-id">
      <input type="hidden" name="board"     id="report-board">
      <div class="compress-modal-info" id="report-info" style="margin-bottom:0.6rem"></div>
      <input type="text" name="reason" id="report-reason"
             placeholder="reason (optional)" maxlength="256"
             style="width:100%;background:var(--bg-input);border:1px solid var(--border);
                    color:var(--text);padding:5px 8px;font-family:var(--font);font-size:0.82rem;
                    box-sizing:border-box;margin-bottom:0.75rem">
      <div class="compress-modal-actions">
        <button type="button" class="compress-cancel-btn" onclick="closeReportModal()">Cancel</button>
        <button type="submit" class="compress-do-btn">&#9873; Submit Report</button>
      </div>
    </form>
  </div>
</div>
<script>
function openReportModal(postId, threadId, board, csrf) {
  document.getElementById('report-post-id').value   = postId;
  document.getElementById('report-thread-id').value = threadId;
  document.getElementById('report-board').value     = board;
  document.getElementById('report-csrf').value      = csrf;
  document.getElementById('report-info').textContent = 'Reporting post No.' + postId;
  document.getElementById('report-reason').value    = '';
  document.getElementById('report-modal').style.display = 'flex';
  document.getElementById('report-reason').focus();
}
function closeReportModal() {
  document.getElementById('report-modal').style.display = 'none';
}
document.getElementById('report-modal').addEventListener('click', function(e) {
  if (e.target === this) closeReportModal();
});
</script>"#
}

// ─── Thread auto-update script ────────────────────────────────────────────────

/// Returns the auto-update JS for thread pages.
/// Includes:
///   • Floating "+N new replies ↓" pill (Feature 1)
///   • Delta-compressed state sync — reply count, lock/sticky via JSON envelope (Feature 2)
///   • "(You)" post tracking via localStorage (Feature 3)
fn thread_autoupdate_script() -> &'static str {
    r#"
<script>
(function() {
  var container  = document.getElementById('thread-posts');
  var statusEl   = document.getElementById('autoupdate-status');
  var timer      = null;
  var updating   = false;
  var autoOn     = false;

  if (!container) return;

  var board    = container.dataset.board;
  var threadId = container.dataset.threadId;
  var lastId   = parseInt(container.dataset.lastId, 10) || 0;

  // ── Feature 1: Floating new-replies pill ─────────────────────────────────
  var pill = document.createElement('div');
  pill.id = 'new-replies-pill';
  pill.className = 'new-replies-pill';
  pill.style.display = 'none';
  document.body.appendChild(pill);

  var pillTimer = null;
  var pillCount = 0;

  function showPill(n) {
    pillCount += n;
    pill.textContent = '+' + pillCount + ' new repl' + (pillCount === 1 ? 'y' : 'ies') + ' \u2193';
    pill.style.display = 'block';
    if (pillTimer) clearTimeout(pillTimer);
    pillTimer = setTimeout(hidePill, 30000);
  }

  function hidePill() {
    pill.style.display = 'none';
    pillCount = 0;
    if (pillTimer) { clearTimeout(pillTimer); pillTimer = null; }
  }

  pill.addEventListener('click', function() {
    window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
    hidePill();
  });

  // Hide pill when user manually scrolls to within 200px of the bottom
  window.addEventListener('scroll', function() {
    if (!pillCount) return;
    var distFromBottom = document.body.scrollHeight - window.scrollY - window.innerHeight;
    if (distFromBottom < 200) hidePill();
  }, { passive: true });

  function setStatus(msg) {
    if (statusEl) statusEl.textContent = msg;
  }

  // ── Feature 2: Delta-state helpers ───────────────────────────────────────

  // Update the reply-count span in the thread nav bar if present.
  function applyDeltaState(data) {
    // Reply count
    var rcEl = document.getElementById('thread-reply-count');
    if (rcEl && data.reply_count !== undefined) {
      rcEl.textContent = data.reply_count;
    }

    // Locked state — inject a lock notice above the posts if newly locked
    if (data.locked) {
      if (!document.getElementById('thread-locked-notice')) {
        var notice = document.createElement('div');
        notice.id = 'thread-locked-notice';
        notice.className = 'notice locked-notice';
        notice.textContent = 'this thread is locked \u2014 no new replies allowed';
        container.parentNode.insertBefore(notice, container);
      }
      // Hide the reply toggle button so the user sees it immediately
      var toggleBar = document.querySelector('.post-toggle-bar.reply');
      if (toggleBar) toggleBar.style.display = 'none';
    }

    // Sticky badge in nav — add/remove a small indicator
    var stickyBadge = document.getElementById('thread-sticky-badge');
    if (data.sticky && !stickyBadge) {
      var badge = document.createElement('span');
      badge.id = 'thread-sticky-badge';
      badge.className = 'tag sticky';
      badge.textContent = 'STICKY';
      badge.style.marginLeft = '0.4rem';
      var navEl = document.querySelector('.board-header.thread-nav');
      if (navEl) navEl.appendChild(badge);
    } else if (!data.sticky && stickyBadge) {
      stickyBadge.remove();
    }
  }

  // ── Main fetch loop ───────────────────────────────────────────────────────
  window.fetchUpdates = function() {
    if (updating) return;
    updating = true;
    setStatus('checking\u2026');
    var url = '/' + board + '/thread/' + threadId + '/updates?since=' + lastId;
    fetch(url, { credentials: 'same-origin' })
      .then(function(r) { return r.ok ? r.json() : Promise.reject(r.status); })
      .then(function(data) {
        if (data.count > 0) {
          var wrap = document.createElement('div');
          wrap.innerHTML = data.html;
          while (wrap.firstChild) container.appendChild(wrap.firstChild);
          lastId = data.last_id;
          container.dataset.lastId = lastId;
          // Wire click-to-collapse on newly added images
          wireImageCollapse(container);
          // Notify other scripts (e.g. quotelink handler, You tracker)
          if (window._onNewPostsInserted) window._onNewPostsInserted(container);
          setStatus('+' + data.count + ' new \u2014 ' + new Date().toLocaleTimeString());
          // Show floating pill only if user isn't already at the bottom
          var distFromBottom = document.body.scrollHeight - window.scrollY - window.innerHeight;
          if (distFromBottom > 200) {
            showPill(data.count);
          }
        } else {
          setStatus('up to date \u2014 ' + new Date().toLocaleTimeString());
        }

        // Always apply delta state so nav bar stays in sync
        applyDeltaState(data);

        updating = false;
      })
      .catch(function(err) {
        setStatus('error (' + err + ')');
        updating = false;
      });
  };

  window.toggleAutoUpdate = function(cb) {
    autoOn = cb.checked;
    if (autoOn) {
      fetchUpdates();
      timer = setInterval(fetchUpdates, 30000);
      setStatus('watching\u2026');
    } else {
      if (timer) { clearInterval(timer); timer = null; }
      setStatus('');
    }
  };

  // Click expanded image to collapse back to thumbnail
  function wireImageCollapse(root) {
    var imgs = root.querySelectorAll('.media-expanded');
    imgs.forEach(function(img) {
      if (img.tagName !== 'IMG') return;
      if (img.dataset.collapseWired) return;
      img.dataset.collapseWired = '1';
      img.style.cursor = 'zoom-out';
      img.addEventListener('click', function() {
        var container = img.closest('.file-container');
        if (!container) return;
        var closeBtn = container.querySelector('.media-close-btn');
        if (closeBtn) collapseMedia(closeBtn);
      });
    });
  }

  // Wire existing images on page load
  wireImageCollapse(document);

  // Re-wire after expand so click-to-collapse is ready when image appears
  var origExpand = window.expandMedia;
  window.expandMedia = function(preview) {
    origExpand(preview);
    var fc = preview.closest('.file-container');
    if (fc) wireImageCollapse(fc);
  };
})();
</script>

<script>
// ── Feature 3: "(You)" post tracking ─────────────────────────────────────────
// Post IDs submitted by this browser are stored in localStorage and displayed
// with a subtle "(You)" badge next to the post number — persisted across reloads.
(function() {
  var container = document.getElementById('thread-posts');
  if (!container) return;

  var board    = container.dataset.board;
  var threadId = container.dataset.threadId;

  var POSTS_KEY   = 'rustchan_my_posts_'   + board + '_' + threadId;
  var PENDING_KEY = 'rustchan_you_pending_' + board + '_' + threadId;

  // ── On page load: if a form submission just completed, capture the new ID ──
  try {
    var pending = localStorage.getItem(PENDING_KEY);
    if (pending === '1') {
      localStorage.removeItem(PENDING_KEY);
      var hash = window.location.hash;
      var m = hash.match(/^#p(\d+)$/);
      if (m) {
        var newId = parseInt(m[1], 10);
        var existing = JSON.parse(localStorage.getItem(POSTS_KEY) || '[]');
        if (existing.indexOf(newId) === -1) existing.push(newId);
        localStorage.setItem(POSTS_KEY, JSON.stringify(existing));
      }
    }
  } catch(e) {}

  // ── Apply (You) badges to every known post on this page ──────────────────
  window._applyYouBadges = function() {
    try {
      var myPosts = JSON.parse(localStorage.getItem(POSTS_KEY) || '[]');
      myPosts.forEach(function(pid) {
        var postEl = document.getElementById('p' + pid);
        if (!postEl) return;
        var postNum = postEl.querySelector('.post-num');
        if (postNum && !postNum.parentNode.querySelector('.you-badge')) {
          var badge = document.createElement('span');
          badge.className = 'you-badge';
          badge.title = 'You posted this';
          badge.textContent = '(You)';
          postNum.insertAdjacentElement('afterend', badge);
        }
      });
    } catch(e) {}
  };

  _applyYouBadges();

  // Re-apply after auto-update inserts new posts (in case one of them is yours
  // via another tab, though the main use is for page-load and manual updates)
  var origInsert = window._onNewPostsInserted;
  window._onNewPostsInserted = function(c) {
    if (origInsert) origInsert(c);
    _applyYouBadges();
  };

  // ── Set the pending flag before form submit so we capture the ID on redirect
  function wireFormTracking() {
    var forms = document.querySelectorAll(
      'form[action*="/thread/' + threadId + '"]'
    );
    forms.forEach(function(form) {
      if (form.dataset.youWired) return;
      form.dataset.youWired = '1';
      form.addEventListener('submit', function() {
        try { localStorage.setItem(PENDING_KEY, '1'); } catch(e) {}
      });
    });
  }
  wireFormTracking();
  // Also wire any forms that appear after the drawer opens
  document.addEventListener('click', function(e) {
    if (e.target && (e.target.id === 'mobile-reply-fab' || e.target.classList.contains('post-toggle-btn'))) {
      setTimeout(wireFormTracking, 150);
    }
  });
})();
</script>"#
}

