// ─── Pagination helper ────────────────────────────────────────────────────────

fn render_pagination(p: &Pagination, base_url: &str) -> String {
    if p.total_pages() <= 1 {
        return String::new();
    }
    let sep = if base_url.contains('?') { "&" } else { "?" };
    let mut html = String::from(r#"<div class="pagination">"#);

    if p.has_prev() {
        html.push_str(&format!(
            r#"<a href="{}{sep}page={}">[prev]</a> "#,
            base_url,
            p.page - 1,
            sep = sep
        ));
    }
    html.push_str(&format!("page {} / {}", p.page, p.total_pages()));
    if p.has_next() {
        html.push_str(&format!(
            r#" <a href="{}{sep}page={}">[next]</a>"#,
            base_url,
            p.page + 1,
            sep = sep
        ));
    }

    html.push_str("</div>");
    html
}

// FIX[LOW-9]: Encode each UTF-8 *byte*, not each Unicode codepoint.
// RFC 3986 percent-encoding operates on bytes. The original implementation
// encoded e.g. 'é' (U+00E9) as %E9 instead of the correct %C3%A9
// (two UTF-8 bytes: 0xC3, 0xA9), producing malformed URLs for non-ASCII input.
fn urlencoding_simple(s: &str) -> String {
    let mut out = String::with_capacity(s.len() * 3);
    for &byte in s.as_bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                out.push(byte as char)
            }
            b' ' => out.push('+'),
            b => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

// ─── Admin VACUUM result page ─────────────────────────────────────────────────

pub fn admin_vacuum_result_page(size_before: i64, size_after: i64, csrf_token: &str) -> String {
    let saved = size_before.saturating_sub(size_after);
    let pct = if size_before > 0 {
        (saved as f64 / size_before as f64 * 100.0) as u64
    } else {
        0
    };

    let body = format!(
        r#"<div class="admin-panel">
<h1>[ VACUUM complete ]</h1>
<section class="admin-section">
<h2>// result</h2>
<table class="admin-table" style="max-width:420px">
<tbody>
  <tr><td>Before</td><td><strong>{before}</strong></td></tr>
  <tr><td>After</td><td><strong>{after}</strong></td></tr>
  <tr><td>Reclaimed</td><td><strong style="color:var(--green-bright)">{saved}</strong> ({pct}%)</td></tr>
</tbody>
</table>
<p style="margin-top:1rem">
  <a href="/admin/panel">&#8592; back to admin panel</a>
</p>
</section>
</div>"#,
        before = format_file_size(size_before),
        after = format_file_size(size_after),
        saved = format_file_size(saved),
        pct = pct,
    );

    // Use a minimal boards list (empty) since we don't need board nav here
    base_layout("VACUUM result", None, &body, csrf_token, &[], false, false)
}

